def apply_severity_overrides(signal: dict, recent_signals: list[dict]) -> str:
    base = signal["raw_severity"]

    # Safety override: always P0
    if signal.get("is_safety_regression"):
        return "P0"

    # High reach override
    wau = signal.get("estimated_users_affected", 0)
    total_wau = signal.get("platform_total_wau", 1)
    if wau / total_wau > 0.05:
        return "P0" if base in ("P0",) else "P1"

    # Recurrence override: 3rd occurrence in 30 days
    same_root_cause = [
        s for s in recent_signals
        if s["affected_component"] == signal["affected_component"]
        and s.get("root_cause_category") == signal.get("root_cause_category")
    ]
    if len(same_root_cause) >= 2:
        escalation_map = {"P3": "P2", "P2": "P1", "P1": "P0", "P0": "P0"}
        return escalation_map.get(base, base)

    return base
